# ── Master list ──────────────────────────────────────────────────────────────

ALL_PROMPTS = (
    FACTUAL_RECALL
    + COUNTERFACTUAL
    + MULTI_STEP
    + LONG_CONTEXT
    + MULTI_TURN
    + INSTRUCTION_FOLLOWING
)

CATEGORIES = [
    "factual_recall",
    "counterfactual",
    "multi_step",
    "long_context",
    "multi_turn",
    "instruction_following",
]

assert len(ALL_PROMPTS) == 300, f"Expected 300 prompts, got {len(ALL_PROMPTS)}"
for cat in CATEGORIES:
    n = sum(1 for p in ALL_PROMPTS if p["category"] == cat)
    assert n == 50, f"Expected 50 prompts for {cat}, got {n}"

# Verify unique IDs
ids = [p["id"] for p in ALL_PROMPTS]
assert len(ids) == len(set(ids)), "Duplicate prompt IDs detected"


def get_by_category(category: str) -> list[dict]:
    """Return prompts for a specific category."""
    return [p for p in ALL_PROMPTS if p["category"] == category]
